const VAT_RATE = 0.24;

const SHELF_LIFE_FIELDS = [
  { key: 'frozen_open', label: '-18 °C avatud pakend' },
  { key: 'frozen_closed', label: '-18 °C suletud pakend' },
  { key: 'cold_open', label: '+2...6 °C avatud pakend' },
  { key: 'cold_closed', label: '+2...6 °C suletud pakend' },
  { key: 'room_open', label: '+7...25 °C avatud pakend' },
  { key: 'room_closed', label: '+7...25 °C suletud pakend' },
  { key: 'vacuum_cold', label: '+2...6 °C vaakumis' },
  { key: 'brine_cold', label: '+2...6 °C soolvees' }
];
const SHELF_LIFE_DEFAULTS = Object.fromEntries(SHELF_LIFE_FIELDS.map(field => [field.key, '']));

const PRODUCT_LABELS = ['Muudatused', 'Uus tarnija', 'Uus toode', 'Uus info', 'Uus hind'];
const LABEL_LIFETIME_MS = 7 * 24 * 60 * 60 * 1000;
const RESTAURANTS = ['Tallinn-1', 'Tallinn-2', 'Tallinn-3', 'Tartu', 'Pärnu'];

const $ = (sel, root = document) => root.querySelector(sel);
const $$ = (sel, root = document) => Array.from(root.querySelectorAll(sel));
const esc = (value='') => String(value ?? '')
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;')
  .replaceAll("'", '&#039;');
const slug = (value='') => String(value ?? '').toLowerCase().trim();
const toNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const normalized = String(value).replace(',', '.').trim();
  const num = Number(normalized);
  return Number.isFinite(num) ? num : null;
};
const fmt = (value, digits = 2) => {
  if (value === null || value === undefined || value === '') return '';
  const num = Number(value);
  if (!Number.isFinite(num)) return String(value);
  return num.toLocaleString('et-EE', { minimumFractionDigits: 0, maximumFractionDigits: digits });
};
const nowIso = () => new Date().toISOString();
const nowText = () => new Date().toLocaleString('et-EE');
const uid = (prefix='id') => `${prefix}-${Math.random().toString(36).slice(2, 10)}-${Date.now().toString(36)}`;
const debounce = (fn, delay = 180) => {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
};

function normalizeShelfLife(value) {
  const next = { ...SHELF_LIFE_DEFAULTS, comment: '', showInTable: false };
  if (!value || typeof value !== 'object') return next;
  for (const field of SHELF_LIFE_FIELDS) next[field.key] = value[field.key] ?? '';
  next.comment = value.comment ?? '';
  next.showInTable = !!value.showInTable;
  return next;
}

function shelfLifeSummary(item) {
  const shelf = normalizeShelfLife(item?.shelfLife);
  const parts = SHELF_LIFE_FIELDS
    .map(field => shelf[field.key] ? `${field.label}: ${shelf[field.key]}` : '')
    .filter(Boolean);
  if (shelf.comment) parts.push(`Kommentaar: ${shelf.comment}`);
  return parts;
}

function normalizeLabels(labels) {
  if (!Array.isArray(labels)) return [];
  const now = Date.now();
  return labels
    .filter(item => item && PRODUCT_LABELS.includes(item.name))
    .filter(item => now - new Date(item.createdAt || 0).getTime() < LABEL_LIFETIME_MS)
    .map(item => ({ name: item.name, createdAt: item.createdAt || nowIso() }));
}

function getActiveLabels(item) {
  return normalizeLabels(item?.labels || []);
}

function upsertTimedLabel(labels, name) {
  const current = normalizeLabels(labels || []);
  const map = new Map(current.map(label => [label.name, label.createdAt]));
  map.set(name, nowIso());
  return Array.from(map.entries()).map(([n, createdAt]) => ({ name: n, createdAt }));
}

function getPriceTrend(item) {
  const history = Array.isArray(item?.priceHistory) ? item.priceHistory.filter(entry => toNumber(entry.price) !== null) : [];
  if (history.length < 2) return null;
  const latest = toNumber(history[history.length - 1].price);
  const previous = toNumber(history[history.length - 2].price);
  if (latest === null || previous === null || previous === 0) return null;
  const diff = latest - previous;
  const percent = diff / previous * 100;
  return { latest, previous, diff, percent };
}

function getCurrentMonthPriceMismatches() {
  const month = monthKey();
  const store = getPriceChecks();
  const monthData = store[month] || {};
  return getMaterials().filter(item => {
    const rowData = monthData[String(item.id)] || {};
    const basePrice = toNumber(item['Hind (ühik km-ta)']);
    const prices = RESTAURANTS.map(name => toNumber(rowData[name])).filter(v => v !== null);
    if (!prices.length) return false;
    if (basePrice !== null) return prices.some(price => price !== basePrice);
    return prices.some(price => price !== prices[0]);
  });
}

function getMaterialIssues(item) {
  const issues = [];
  if (!item?.Tarnija) issues.push('Tarnija puudub');
  if (toNumber(item?.['Hind (ühik km-ta)']) === null) issues.push('Hind puudub');
  const shelf = normalizeShelfLife(item?.shelfLife);
  if (shelf.showInTable && !SHELF_LIFE_FIELDS.some(field => shelf[field.key])) issues.push('Säilivus puudub');
  return issues;
}

function getProblemSummary() {
  const materials = getMaterials();
  const noPrice = materials.filter(item => toNumber(item['Hind (ühik km-ta)']) === null);
  const noSupplier = materials.filter(item => !String(item.Tarnija || '').trim());
  const noShelf = materials.filter(item => {
    const shelf = normalizeShelfLife(item.shelfLife);
    return shelf.showInTable && !SHELF_LIFE_FIELDS.some(field => String(shelf[field.key] || '').trim());
  });
  const priceDiffs = getCurrentMonthPriceMismatches();
  return { noPrice, noSupplier, noShelf, priceDiffs };
}

function applyAutoLabels(saved, existing) {
  let labels = normalizeLabels(saved.labels || existing?.labels || []);
  if (!existing) {
    labels = upsertTimedLabel(labels, 'Uus toode');
    return labels;
  }
  const diffs = diffEntries(existing, saved).filter(([field]) => !['labels','lastModifiedAt','lastModifiedBy'].includes(field));
  if (diffs.length) labels = upsertTimedLabel(labels, 'Muudatused');
  if (diffs.some(([field]) => field === 'Hind (ühik km-ta)')) labels = upsertTimedLabel(labels, 'Uus hind');
  if (diffs.some(([field]) => field === 'Tarnija')) labels = upsertTimedLabel(labels, 'Uus tarnija');
  if (diffs.some(([field]) => ['Kommentaar','Allergeenid','Toode','Kood','shelfLife'].includes(field))) labels = upsertTimedLabel(labels, 'Uus info');
  return labels;
}

function getSupplierStats() {
  const materials = getMaterials();
  return getSuppliers().map(supplier => {
    const items = materials.filter(item => item.Tarnija === supplier.Tarnija);
    const issues = items.filter(item => getMaterialIssues(item).length);
    const changed = items.filter(item => Array.isArray(item.priceHistory) && item.priceHistory.length > 1);
    const trendItems = items.map(item => getPriceTrend(item)).filter(Boolean);
    const avgChange = trendItems.length ? trendItems.reduce((acc, item) => acc + item.percent, 0) / trendItems.length : 0;
    return {
      name: supplier.Tarnija,
      products: items.length,
      issues: issues.length,
      changed: changed.length,
      avgChange
    };
  }).sort((a,b) => a.name.localeCompare(b.name,'et'));
}

function labelsMarkup(item) {
  const labels = getActiveLabels(item);
  if (!labels.length) return '';
  return `<div class="chip-row">${labels.map(label => `<span class="status-chip">${esc(label.name)}</span>`).join('')}</div>`;
}

function monthKey(value) {
  const d = value ? new Date(value) : new Date();
  if (Number.isNaN(d.getTime())) return new Date().toISOString().slice(0, 7);
  return d.toISOString().slice(0, 7);
}

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function loadData(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : clone(fallback);
  } catch (e) {
    return clone(fallback);
  }
}

function saveData(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
  window.AppDB?.queueStateSave?.(key, value);
}

function normalizeMaterial(item, index = 0) {
  const material = {
    id: item?.id ?? index + 1,
    Tooraine: item?.Tooraine ?? '',
    'Ühik': item?.['Ühik'] ?? '',
    'Hind (ühik km-ta)': item?.['Hind (ühik km-ta)'] ?? null,
    'Pakendi hind': item?.['Pakendi hind'] ?? null,
    Tarnija: item?.Tarnija ?? '',
    Kood: item?.Kood ?? '',
    Kommentaar: item?.Kommentaar ?? '',
    Toode: item?.Toode ?? '',
    'Neto kaal (gr)': item?.['Neto kaal (gr)'] ?? null,
    Kcal: item?.Kcal ?? null,
    Valgud: item?.Valgud ?? null,
    Rasvad: item?.Rasvad ?? null,
    Süsivesik: item?.Süsivesik ?? null,
    Allergeenid: item?.Allergeenid ?? '',
    Taaras: item?.Taaras ?? '',
    shelfLife: normalizeShelfLife(item?.shelfLife),
    alternatiivid: Array.isArray(item?.alternatiivid) ? item.alternatiivid.map(a => ({
      id: a?.id ?? uid('alt'),
      Tooraine: a?.Tooraine ?? '',
      Tarnija: a?.Tarnija ?? '',
      Hind: a?.Hind ?? null,
      Kood: a?.Kood ?? '',
      Taaras: a?.Taaras ?? ''
    })) : [],
    priceHistory: Array.isArray(item?.priceHistory) ? item.priceHistory : [],
    changeHistory: Array.isArray(item?.changeHistory) ? item.changeHistory : [],
    lastModifiedAt: item?.lastModifiedAt ?? null,
    lastModifiedBy: item?.lastModifiedBy ?? '',
    labels: normalizeLabels(item?.labels)
  };
  if (!material.priceHistory.length) {
    material.priceHistory.push({ date: 'Algimport', price: material['Hind (ühik km-ta)'] ?? null });
  }
  return material;
}

function getMaterials() {
  const items = loadData(APP_KEYS.materials, INITIAL_RAW_MATERIALS).map(normalizeMaterial);
  return items.sort((a, b) => String(a.id).localeCompare(String(b.id), 'et', {numeric: true}));
}

function setMaterials(items, silent = false) {
  saveData(APP_KEYS.materials, items.map(normalizeMaterial));
  if (!silent) touchMeta();
}

function getSuppliers() {
  const materials = getMaterials();
  const current = loadData(APP_KEYS.suppliers, INITIAL_SUPPLIERS).map((item, index) => ({
    id: item?.id ?? index + 1,
    Tarnija: item?.Tarnija ?? '',
    'Müügiesindaja': item?.['Müügiesindaja'] ?? '',
    Kontakt: item?.Kontakt ?? '',
    Veebileht: item?.Veebileht ?? '',
    'E-post': item?.['E-post'] ?? '',
    'Tarne Tartu': item?.['Tarne Tartu'] ?? '',
    'Tarne Tallinn': item?.['Tarne Tallinn'] ?? '',
    'Tarne Pärnu': item?.['Tarne Pärnu'] ?? '',
    'Minimaalne tellimus': item?.['Minimaalne tellimus'] ?? '',
    Kommentaarid: item?.Kommentaarid ?? '',
    'Tartu Login': item?.['Tartu Login'] ?? '',
    'Tartu Parool': item?.['Tartu Parool'] ?? '',
    'Tallinn Login': item?.['Tallinn Login'] ?? '',
    'Tallinn Parool': item?.['Tallinn Parool'] ?? '',
    'Pärnu Login': item?.['Pärnu Login'] ?? '',
    'Pärnu Parool': item?.['Pärnu Parool'] ?? ''
  }));
  const existing = new Map(current.map(s => [s.Tarnija, s]));
  materials.forEach(material => {
    const name = (material.Tarnija || '').trim();
    if (name && !existing.has(name)) {
      existing.set(name, {
        id: uid('supplier'),
        Tarnija: name,
        'Müügiesindaja': '',
        Kontakt: '',
        Veebileht: '',
        'E-post': '',
        'Tarne Tartu': '',
        'Tarne Tallinn': '',
        'Tarne Pärnu': '',
        'Minimaalne tellimus': '',
        Kommentaarid: '',
        'Tartu Login': '',
        'Tartu Parool': '',
        'Tallinn Login': '',
        'Tallinn Parool': '',
        'Pärnu Login': '',
        'Pärnu Parool': ''
      });
    }
  });
  return Array.from(existing.values()).sort((a,b) => (a.Tarnija || '').localeCompare(b.Tarnija || '', 'et'));
}

function setSuppliers(items, silent = false) {
  saveData(APP_KEYS.suppliers, items);
  if (!silent) touchMeta();
}

function getUsers() {
  const users = loadData(APP_KEYS.users, [DEFAULT_SUPER_USER]);
  if (window.AppAuth?.isEnabled?.()) {
    return users;
  }
  if (!users.some(user => user.login === DEFAULT_SUPER_USER.login)) {
    users.push(clone(DEFAULT_SUPER_USER));
    saveData(APP_KEYS.users, users);
  }
  return users;
}

function setUsers(users) {
  saveData(APP_KEYS.users, users);
}

function getLogs() {
  return loadData(APP_KEYS.logs, []);
}

function setLogs(logs) {
  saveData(APP_KEYS.logs, logs);
}

function getSettings() {
  const settings = loadData(APP_KEYS.settings, DEFAULT_SETTINGS);
  settings.targets = { ...DEFAULT_SETTINGS.targets, ...(settings.targets || {}) };
  return settings;
}

function setSettings(settings) {
  saveData(APP_KEYS.settings, settings);
}

function getGeneratedFiles() {
  return loadData(APP_KEYS.generatedFiles, []);
}

function setGeneratedFiles(files) {
  saveData(APP_KEYS.generatedFiles, files);
}

function getPriceChecks() {
  return loadData(APP_KEYS.priceChecks, {});
}

function setPriceChecks(value) {
  saveData(APP_KEYS.priceChecks, value);
}

function getInternalNotes() {
  return loadData(APP_KEYS.internalNotes, []);
}

function setInternalNotes(notes) {
  saveData(APP_KEYS.internalNotes, notes);
}

function getPriceSnapshots() {
  const currentYear = new Date().getFullYear();
  const store = loadData(APP_KEYS.priceSnapshots, { year: currentYear, months: {} });
  if (!store.year || Number(store.year) !== currentYear) {
    const next = { year: currentYear, months: {} };
    saveData(APP_KEYS.priceSnapshots, next);
    return next;
  }
  store.months = store.months || {};
  return store;
}

function setPriceSnapshots(store) {
  saveData(APP_KEYS.priceSnapshots, store);
}

function ensureCurrentMonthPriceSnapshot() {
  const store = getPriceSnapshots();
  const currentMonth = monthKey();
  if (store.months[currentMonth]) return;
  const snapshot = {};
  getMaterials().forEach(item => {
    snapshot[String(item.id)] = toNumber(item['Hind (ühik km-ta)']);
  });
  store.months[currentMonth] = {
    capturedAt: nowIso(),
    prices: snapshot
  };
  setPriceSnapshots(store);
}

function getYearMonthKeys(year = new Date().getFullYear()) {
  return Array.from({ length: 12 }, (_, index) => `${year}-${String(index + 1).padStart(2, '0')}`);
}

function getPriceAnalyticsRows() {
  const store = getPriceSnapshots();
  const months = getYearMonthKeys(store.year);
  return getMaterials().map(item => {
    const monthly = months.map(month => ({ month, value: toNumber(store.months?.[month]?.prices?.[String(item.id)]) }));
    const filled = monthly.filter(entry => entry.value !== null);
    const first = filled[0]?.value ?? null;
    const last = filled[filled.length - 1]?.value ?? null;
    const diff = first !== null && last !== null ? last - first : null;
    const percent = diff !== null && first ? (diff / first * 100) : null;
    return { item, monthly, first, last, diff, percent };
  });
}

function rememberGeneratedFile(file) {
  const files = getGeneratedFiles();
  files.unshift(file);
  setGeneratedFiles(files.slice(0, 20));
}

function getMeta() {
  return loadData(APP_KEYS.meta, { lastChangedAt: null });
}

function touchMeta() {
  const meta = getMeta();
  meta.lastChangedAt = nowIso();
  saveData(APP_KEYS.meta, meta);
}

function getCurrentUser() {
  const session = loadData(APP_KEYS.session, null);
  if (!session?.login) return null;
  return getUsers().find(user => user.login === session.login) || null;
}

function setCurrentUser(user) {
  saveData(APP_KEYS.session, { login: user.login });
  const users = getUsers();
  const idx = users.findIndex(item => item.login === user.login);
  if (idx >= 0) {
    users[idx] = { ...users[idx], lastLoginAt: nowIso(), lastActiveAt: nowIso() };
    setUsers(users);
  }
}

function markCurrentUserSeen(page = '') {
  const session = loadData(APP_KEYS.session, null);
  if (!session?.login) return;
  const users = getUsers();
  const idx = users.findIndex(item => item.login === session.login);
  if (idx >= 0) {
    const prev = users[idx].lastActiveAt ? new Date(users[idx].lastActiveAt).getTime() : 0;
    const now = Date.now();
    if (!prev || now - prev > 30000 || users[idx].lastPage !== page) {
      users[idx] = { ...users[idx], lastActiveAt: nowIso(), lastPage: page || users[idx].lastPage || '' };
      setUsers(users);
    }
  }
}

async function logout() {
  if (window.AppAuth?.isEnabled?.()) {
    await window.AppAuth.logout();
    return;
  }
  localStorage.removeItem(APP_KEYS.session);
  location.href = 'index.html';
}

function fullName(user) {
  return [user?.firstName || '', user?.lastName || ''].join(' ').trim() || user?.login || 'Kasutaja';
}

function logAction(type, target, name, message, extra = {}) {
  const user = getCurrentUser();
  const logs = getLogs();
  logs.unshift({
    id: uid('log'),
    at: nowIso(),
    atText: nowText(),
    userLogin: user?.login || 'system',
    userName: fullName(user) || 'System',
    type,
    target,
    name,
    message,
    extra
  });
  setLogs(logs.slice(0, 2000));
}

function diffEntries(before, after) {
  const keys = Array.from(new Set([...Object.keys(before || {}), ...Object.keys(after || {})]));
  return keys
    .filter(key => JSON.stringify(before?.[key] ?? null) !== JSON.stringify(after?.[key] ?? null))
    .map(key => [key, before?.[key] ?? null, after?.[key] ?? null]);
}

function ensureAuth() {
  const isLoginPage = location.pathname.endsWith('index.html') || location.pathname.endsWith('/');
  const user = getCurrentUser();
  if (!isLoginPage && !user) {
    location.href = 'index.html';
    return false;
  }
  return true;
}

function ensureSuperUser() {
  const user = getCurrentUser();
  if (!user?.isSuper) {
    document.body.innerHTML = `<div class="login-page"><div class="login-card"><h1>Ligipääs puudub</h1><p>Sellele lehele pääseb ainult superkasutaja.</p><div class="row-actions"><a class="button secondary" href="toorained.html">Tagasi</a></div></div></div>`;
    return false;
  }
  return true;
}

function headerLayout(active) {
  const user = getCurrentUser();
  const adminLink = user?.isSuper ? `<a class="${active === 'admin' ? 'active' : ''}" href="admin.html">Administreerimine</a>` : '';
  return `
    <header class="topbar-shell no-print">
      <div class="topbar-inner">
        <div class="brand">
          <div class="brand-mark">TT</div>
          <div>
            <h1>Tooraine töölaud</h1>
            <p>Registrid, kalkulaator ja administreerimine</p>
          </div>
        </div>
        <nav class="main-nav">
          <a class="${active === 'toorained' ? 'active' : ''}" href="toorained.html">Toorained</a>
          <a class="${active === 'tarnijad' ? 'active' : ''}" href="tarnijad.html">Tarnijad</a>
          <a class="${active === 'shelf-life' ? 'active' : ''}" href="sailivus.html">Säilivus</a>
          <a class="${active === 'price-control' ? 'active' : ''}" href="hinnakontroll.html">Hinnakontroll</a>
          <a class="${active === 'kalk' ? 'active' : ''}" href="uc-kalkulaator.html">UC kalkulaator</a>
          ${adminLink}
        </nav>
        <div class="userbox">
          <div><strong>${esc(fullName(user))}</strong><span>${esc(user?.login || '')}</span></div>
          <button class="button ghost" id="logoutBtn">Logi välja</button>
        </div>
      </div>
    </header>
    <main class="page-shell" id="pageRoot"></main>
    <div class="modal-backdrop" id="modalBackdrop"><div class="modal-box" id="modalBox"></div></div>
  `;
}

function bindGlobalUI() {
  $('#logoutBtn')?.addEventListener('click', logout);
  $('#modalBackdrop')?.addEventListener('click', (event) => {
    if (event.target.id === 'modalBackdrop') closeModal();
  });
}

function openModal(html, onReady) {
  $('#modalBox').innerHTML = html;
  $('#modalBackdrop').classList.add('show');
  onReady?.();
}

function closeModal() {
  $('#modalBackdrop')?.classList.remove('show');
}

function showToast(text) {
  let toast = document.createElement('div');
  toast.className = 'toast';
  toast.textContent = text;
  document.body.appendChild(toast);
  requestAnimationFrame(() => toast.classList.add('show'));
  setTimeout(() => {
    toast.classList.remove('show');
    setTimeout(() => toast.remove(), 300);
  }, 2400);
}

function supplierOptions(selected = '') {
  return `<option value="">Vali tarnija</option>` + getSuppliers().map(s => `<option value="${esc(s.Tarnija)}" ${s.Tarnija === selected ? 'selected' : ''}>${esc(s.Tarnija)}</option>`).join('');
}

function materialSelectOptions(selectedId = '') {
  return `<option value="">Vali tooraine</option>` + getMaterials().map(m => `<option value="${esc(m.id)}" ${String(m.id) === String(selectedId) ? 'selected' : ''}>${esc(m.Tooraine)} · ${esc(m.Tarnija || '-')} · ${esc(m.Kood || '')}</option>`).join('');
}

function getLastChangedText() {
  const meta = getMeta();
  return meta.lastChangedAt ? new Date(meta.lastChangedAt).toLocaleString('et-EE') : '—';
}

function renderLoginPage() {
  document.body.innerHTML = `
    <div class="login-page">
      <div class="login-shell">
        <section class="login-side">
          <div class="hero-badge">TT</div>
          <h1>Tooraine töölaud</h1>
          <p>Mugav ligipääs toorainetele, tarnijatele, kalkulaatorile ja haldusele ühest kohast.</p>
          <div class="login-feature-list">
            <div class="login-feature"><strong>Toorained</strong><span>Muuda tooteid, koode, hindu ja jälgi ajalugu.</span></div>
            <div class="login-feature"><strong>UC kalkulaator</strong><span>Arvuta omahind, KБЖУ ja loo PDF-fail ühelt lehelt.</span></div>
            <div class="login-feature"><strong>Administreerimine</strong><span>Halda kasutajaid, impordi andmeid ja vaata logisid.</span></div>
          </div>
        </section>
        <section class="login-card">
          <h2>Logi sisse</h2>
          <p>${window.AppAuth?.isEnabled?.() ? 'Kasuta e-posti ja parooli.' : 'Kasuta oma kasutajanime ja parooli.'}</p>
          <form id="loginForm" class="login-form">
            <div class="form-grid single">
              <label><span>${window.AppAuth?.isEnabled?.() ? 'E-post' : 'Kasutajanimi'}</span><input id="loginName" autocomplete="username" placeholder="${window.AppAuth?.isEnabled?.() ? 'Sisesta e-post' : 'Sisesta kasutajanimi'}"></label>
              <label><span>Parool</span><div class="password-field"><input id="loginPassword" type="password" autocomplete="current-password" placeholder="Sisesta parool"><button type="button" class="button ghost small" id="togglePasswordBtn">Näita</button></div></label>
            </div>
            <div class="row-actions login-actions">
              <button class="button wide" id="loginBtn" type="submit">Sisene</button>
            </div>
          </form>
          <div id="loginMessage" class="hint"></div>
        </section>
      </div>
    </div>
  `;
  const loginInput = $('#loginName');
  const passwordInput = $('#loginPassword');
  const message = $('#loginMessage');
  const handleLogin = async (event) => {
    event?.preventDefault?.();
    const login = loginInput.value.trim();
    const password = passwordInput.value.trim();
    message.textContent = '';
    message.classList.remove('error');
    if (window.AppAuth?.isEnabled?.()) {
      try {
        await window.AppAuth.login(login, password);
        location.href = 'toorained.html';
      } catch (error) {
        message.textContent = error?.message || 'Sisselogimine ebaõnnestus.';
        message.classList.add('error');
      }
      return;
    }
    const user = getUsers().find(item => item.login === login && item.password === password);
    if (!user) {
      message.textContent = 'Vale kasutajanimi või parool.';
      message.classList.add('error');
      passwordInput.focus();
      passwordInput.select();
      return;
    }
    setCurrentUser(user);
    logAction('login', 'auth', user.login, 'Kasutaja logis sisse');
    location.href = 'toorained.html';
  };
  $('#loginForm').addEventListener('submit', handleLogin);
  $('#togglePasswordBtn').addEventListener('click', () => {
    const showing = passwordInput.type === 'text';
    passwordInput.type = showing ? 'password' : 'text';
    $('#togglePasswordBtn').textContent = showing ? 'Näita' : 'Peida';
    passwordInput.focus();
  });
  loginInput.focus();
}

