async function downloadKalkPdf() {
  if (!window.html2canvas || !window.jspdf?.jsPDF) {
    showToast('PDF teek ei ole laaditud');
    return;
  }
  const state = getKalkState();
  const materials = getMaterials();
  const settings = getSettings();
  const totals = state.rows.reduce((acc, row) => {
    const item = materials.find(mat => String(mat.id) === String(row.materialId));
    const calc = computeRow(item, row.qty);
    acc.cost += calc.cost;
    acc.kcal += calc.kcal;
    acc.protein += calc.protein;
    acc.fat += calc.fat;
    acc.carbs += calc.carbs;
    acc.weightGr += calc.weightGr;
    calc.allergens.forEach(a => acc.allergens.add(a));
    acc.rows.push({ row, item, calc });
    return acc;
  }, { cost: 0, kcal: 0, protein: 0, fat: 0, carbs: 0, weightGr: 0, allergens: new Set(), rows: [] });

  const per100 = totals.weightGr > 0 ? {
    kcal: totals.kcal / totals.weightGr * 100,
    protein: totals.protein / totals.weightGr * 100,
    fat: totals.fat / totals.weightGr * 100,
    carbs: totals.carbs / totals.weightGr * 100
  } : { kcal: 0, protein: 0, fat: 0, carbs: 0 };
  const targetPercent = toNumber(settings.targets[state.productType]) || 25;
  const suggested = targetPercent > 0 ? totals.cost / (targetPercent / 100) : 0;
  const withVat = totals.cost * (1 + VAT_RATE);
  const filenameBase = (state.productName || 'uc-kalkulaator').trim().replace(/[^a-zA-Z0-9äöüõÄÖÜÕ\-_ ]/g, '').replace(/\s+/g, '_') || 'uc-kalkulaator';

  const wrapper = document.createElement('div');
  wrapper.className = 'pdf-capture-root';
  wrapper.innerHTML = renderPdfPreviewHtml(state, totals, per100, withVat, suggested, targetPercent);
  document.body.appendChild(wrapper);

  try {
    const target = wrapper.querySelector('.pdf-sheet');
    const canvas = await window.html2canvas(target, { scale: 2, backgroundColor: '#f5f7fb', useCORS: true });
    const imgData = canvas.toDataURL('image/png');
    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pageWidth = pdf.internal.pageSize.getWidth();
    const pageHeight = pdf.internal.pageSize.getHeight();
    const margin = 8;
    const imgWidth = pageWidth - margin * 2;
    const imgHeight = canvas.height * imgWidth / canvas.width;
    let heightLeft = imgHeight;
    let position = margin;

    pdf.addImage(imgData, 'PNG', margin, position, imgWidth, imgHeight, undefined, 'FAST');
    heightLeft -= (pageHeight - margin * 2);

    while (heightLeft > 0) {
      pdf.addPage();
      position = margin - (imgHeight - heightLeft);
      pdf.addImage(imgData, 'PNG', margin, position, imgWidth, imgHeight, undefined, 'FAST');
      heightLeft -= (pageHeight - margin * 2);
    }

    pdf.save(`${filenameBase}.pdf`);
    const dataUri = pdf.output('datauristring');
    rememberGeneratedFile({
      id: uid('pdf'),
      name: `${filenameBase}.pdf`,
      createdAt: nowIso(),
      createdAtText: nowText(),
      type: 'application/pdf',
      source: 'UC kalkulaator',
      productName: state.productName || '—',
      dataUri
    });
    logAction('export', 'calculator', state.productName || 'UC kalkulaator', 'PDF fail genereeriti kalkulaatorist');
    showToast('PDF fail on loodud');
  } catch (error) {
    console.error(error);
    showToast('PDF faili loomine ebaõnnestus');
  } finally {
    wrapper.remove();
  }
}

