  function renderCalcRow(row) {
    const materials = getMaterials();
    const item = materials.find(mat => String(mat.id) === String(row.materialId));
    const calc = computeRow(item, row.qty);
    return `
      <tr data-rowid="${esc(row.id)}">
        <td><select data-role="material">${materialSelectOptions(row.materialId)}</select></td>
        <td class="num" data-cell="price">${fmt(item?.['Hind (ühik km-ta)'])}</td>
        <td data-cell="code">${esc(item?.Kood || '')}</td>
        <td data-cell="supplier">${esc(item?.Tarnija || '')}</td>
        <td><input data-role="qty" inputmode="decimal" value="${esc(row.qty || '')}" placeholder="${(slug(item?.['Ühik']) === 'kg' || slug(item?.['Ühik']) === 'l') ? 'gr / ml' : 'tk'}"></td>
        <td class="num" data-cell="cost">${fmt(calc.cost)}</td>
        <td class="num" data-cell="kcal">${fmt(calc.kcal)}</td>
        <td class="num" data-cell="protein">${fmt(calc.protein)}</td>
        <td class="num" data-cell="fat">${fmt(calc.fat)}</td>
        <td class="num" data-cell="carbs">${fmt(calc.carbs)}</td>
        <td><button class="icon-btn" title="Dubleeri rida" data-duplicate-row="${esc(row.id)}">⧉</button></td><td><button class="icon-btn danger-text" data-remove-row="${esc(row.id)}">✕</button></td>
      </tr>
    `;
  }

  function bindCalcRowEvents(scope = document) {
    scope.querySelectorAll('#calcRows select[data-role="material"]').forEach(select => {
      if (select.dataset.bound === '1') return;
      select.dataset.bound = '1';
      select.addEventListener('change', () => {
        const state = getKalkState();
        const row = state.rows.find(item => item.id === select.closest('tr').dataset.rowid);
        if (!row) return;
        row.materialId = select.value;
        setKalkState(state);
        redraw();
      });
    });
    scope.querySelectorAll('#calcRows input[data-role="qty"]').forEach(input => {
      if (input.dataset.bound === '1') return;
      input.dataset.bound = '1';
      input.addEventListener('input', () => {
        const tr = input.closest('tr');
        const state = getKalkState();
        const row = state.rows.find(item => item.id === tr.dataset.rowid);
        if (!row) return;
        row.qty = input.value;
        setKalkState(state);
        const item = getMaterials().find(mat => String(mat.id) === String(row.materialId));
        const calc = computeRow(item, row.qty);
        tr.querySelector('[data-cell="price"]').textContent = fmt(item?.['Hind (ühik km-ta)']);
        tr.querySelector('[data-cell="code"]').textContent = item?.Kood || '';
        tr.querySelector('[data-cell="supplier"]').textContent = item?.Tarnija || '';
        tr.querySelector('[data-cell="cost"]').textContent = fmt(calc.cost);
        tr.querySelector('[data-cell="kcal"]').textContent = fmt(calc.kcal);
        tr.querySelector('[data-cell="protein"]').textContent = fmt(calc.protein);
        tr.querySelector('[data-cell="fat"]').textContent = fmt(calc.fat);
        tr.querySelector('[data-cell="carbs"]').textContent = fmt(calc.carbs);
        redrawSummary();
      });
    });
    scope.querySelectorAll('#calcRows [data-duplicate-row]').forEach(btn => {
      if (btn.dataset.bound === '1') return;
      btn.dataset.bound = '1';
      btn.addEventListener('click', () => {
        const state = getKalkState();
        const src = state.rows.find(item => item.id === btn.dataset.duplicateRow);
        if (!src) return;
        state.rows.push({ ...src, id: uid('row') });
        setKalkState(state);
        redraw();
      });
    });
    scope.querySelectorAll('#calcRows [data-remove-row]').forEach(btn => {
      if (btn.dataset.bound === '1') return;
      btn.dataset.bound = '1';
      btn.addEventListener('click', () => {
        const state = getKalkState();
        state.rows = state.rows.filter(item => item.id !== btn.dataset.removeRow);
        if (!state.rows.length) state.rows.push({ id: uid('row'), materialId: '', qty: '' });
        setKalkState(state);
        redraw();
      });
    });
  }

  function redraw() {
    const current = getKalkState();
    $('#calcRows').innerHTML = current.rows.map(renderCalcRow).join('');
    bindCalcRowEvents(document);
    redrawSummary();
  }

